class StaleModelException extends RuntimeException {
    public function __construct(public readonly Model $model) {
        parent::__construct('The model has been modified by another process');
    }
    public function report(): void {
        Log::warning('Stale model detected', [
            'model' => get_class($this->model),
            'id' => $this->model->getKey(),
        ]);
    }
    public function render(Request $request): JsonResponse {
        return response()->json([
            'error' => 'Data has been modified. Please refresh and try again.',
        ], 409);
    }
}

