class StripePaymentAdapter implements PaymentGateway {
    public function charge(Money $amount, string $token): PaymentResult {
        try {
            $charge = \Stripe\Charge::create([...]);
            return new PaymentResult(true, $charge->id);
        } catch (\Stripe\Exception\CardException $e) {
            throw new CardDeclinedException($e->getMessage(), previous: $e);
        } catch (\Stripe\Exception\ApiErrorException $e) {
            throw new PaymentGatewayException('Stripe API error', previous: $e);
        }
    }
}

