Code Good:
class ProcessPayment implements ShouldQueue {
    public int $tries = 3;
    public array $backoff = [10, 60, 300]; // seconds

    public function handle(PaymentGateway $gateway): void {
        $gateway->charge($this->order->total);
        $this->order->markAsPaid();
    }

    public function failed(Throwable $e): void {
        Log::error('Payment job failed permanently', [
            'order_id' => $this->order->id,
            'error' => $e->getMessage(),
        ]);
        $this->order->markAsFailed();
        Notification::send($this->order->user, new PaymentFailedNotification($this->order));
    }
}

